   108→  // Actions - Tags
   109→  addTag: (id: string, tag: string) => void;
   110→  removeTag: (id: string, tag: string) => void;
   111→  getAllTags: () => string[];
   112→
   113→  // Actions - UI state
   114→  setActiveNote: (id: string | null) => void;
   115→  setSortConfig: (config: NoteSortConfig) => void;
   116→  setFilter: (filter: NoteFilter) => void;
   117→
   118→  // Actions - Utility
   119→  getNoteCount: () => number;
   120→  getNotesInFolder: (folderId: string | null) => Note[];
   121→  exportNotes: () => Note[];
   122→  importNotes: (notes: Note[], merge: boolean) => void;
   123→  clearAllNotes: () => void;
   124→
   125→  // Actions - Backlinks (Phase 4)
   126→  getBacklinks: (noteId: string) => Note[];
   127→  updateLinkedNotes: (noteId: string, content: string) => void;
   128→
   129→  // Actions - Templates (Phase 4)
   130→  getNoteTemplates: () => NoteTemplate[];
   131→  createNoteFromTemplate: (templateId: string) => Note | null;
   132→}
   133→
   134→/**
   135→ * Default note values
   136→ */
   137→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   138→  const now = new Date();
   139→  return {
   140→    id: uuidv4(),
   141→    folderId: null,
   142→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   143→    content: '', // Empty Lexical state
   144→    contentText: '',
   145→    tags: [],
   146→    createdAt: now,
   147→    updatedAt: now,
   148→    isPinned: false,
   149→    isArchived: false,
   150→    ...overrides,
   151→  };
   152→};
   153→
   154→/**
   155→ * Sort notes based on sort config
   156→ */
   157→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   158→  const sorted = [...notes];
   159→
   160→  sorted.sort((a, b) => {
   161→    let comparison = 0;
   162→
   163→    switch (config.field) {
   164→      case 'title':
   165→        comparison = a.title.localeCompare(b.title);
   166→        break;
   167→      case 'createdAt':
   168→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   169→        break;
   170→      case 'updatedAt':
   171→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   172→        break;
   173→      case 'manual':
   174→        // Manual sort - preserve order (could add sortOrder field in future)
   175→        comparison = 0;
   176→        break;
   177→    }
   178→
   179→    return config.order === 'asc' ? comparison : -comparison;
   180→  });
   181→
   182→  // Always pin pinned notes to top
   183→  return sorted.sort((a, b) => {
   184→    if (a.isPinned && !b.isPinned) return -1;
   185→    if (!a.isPinned && b.isPinned) return 1;
   186→    return 0;
   187→  });
   188→};
   189→
   190→/**
   191→ * Filter notes based on filter type
   192→ */
   193→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   194→  switch (filter) {
   195→    case 'favorites':
   196→      return notes.filter((note) => note.isFavorite);
   197→    case 'pinned':
   198→      return notes.filter((note) => note.isPinned);
   199→    case 'archived':
   200→      return notes.filter((note) => note.isArchived);
   201→    case 'unarchived':
   202→      return notes.filter((note) => !note.isArchived);
   203→    case 'all':
   204→    default:
   205→      return notes;
   206→  }
   207→};
   208→
   209→/**
   210→ * Create the Notes store
   211→ */
   212→export const useNotesStore = create<NotesStore>()(
   213→  persist(
   214→    (set, get) => ({
   215→      // Initial state
   216→      notes: {},
   217→      activeNoteId: null,
   218→      sortConfig: {
   219→        field: 'updatedAt',
   220→        order: 'desc',
   221→      },
   222→      filter: 'unarchived',
   223→
   224→      // CRUD Operations
   225→      createNote: (params) => {
   226→        const newNote = createDefaultNote(params);
   227→        set((state) => ({
   228→          notes: {
   229→            ...state.notes,
   230→            [newNote.id]: newNote,
   231→          },
   232→          activeNoteId: newNote.id, // Auto-select new note
   233→        }));
   234→        console.log('✅ Note created:', newNote.id);
   235→        return newNote;
   236→      },
   237→
   238→      getNote: (id) => {
   239→        return get().notes[id];
   240→      },
   241→
   242→      updateNote: (id, updates) => {
   243→        const note = get().notes[id];
   244→        if (!note) {
   245→          console.warn(`Note ${id} not found`);
   246→          return;
   247→        }
   248→
   249→        // Only update timestamp if content/title/tags actually changed
   250→        // Skip timestamp update for UI-only changes (like folderId without content change)
   251→        const shouldUpdateTimestamp =
   252→          updates.content !== undefined ||
   253→          updates.title !== undefined ||
   254→          updates.tags !== undefined;
   255→
   256→        set((state) => ({
   257→          notes: {
   258→            ...state.notes,
   259→            [id]: {
   260→              ...note,
   261→              ...updates,
   262→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   263→            },
   264→          },
   265→        }));
   266→        console.log('✅ Note updated:', id, shouldUpdateTimestamp ? '(timestamp updated)' : '(no timestamp change)');
   267→      },
   268→
   269→      deleteNote: (id) => {
   270→        // Save note for undo
   271→        const noteToDelete = get().notes[id];
   272→        if (!noteToDelete) {
   273→          console.warn(`Note ${id} not found`);
   274→          return;
   275→        }
   276→
   277→        // Store the previous activeNoteId for undo
   278→        const wasActive = get().activeNoteId === id;
   279→
   280→        // Delete the note
   281→        set((state) => {
   282→          const { [id]: deleted, ...remainingNotes } = state.notes;
   283→          return {
   284→            notes: remainingNotes,
   285→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   286→          };
   287→        });
   288→
   289→        console.log('✅ Note deleted:', id);
   290→
   291→        // Delete associated images from IndexedDB (async, fire-and-forget)
   292→        import('../services/indexedDB').then(({ indexedDBService }) => {
   293→          indexedDBService.deleteNoteImages(id).catch((err) => {
   294→            console.error('Failed to delete note images:', err);
   295→          });
   296→        });
   297→
   298→        // Add undo action
   299→        useUndoStore.getState().addUndoAction(
   300→          `Note "${noteToDelete.title}" deleted`,
   301→          () => {
   302→            // Restore the note
   303→            set((state) => ({
   304→              notes: {
   305→                ...state.notes,
   306→                [id]: noteToDelete,
   307→              },
   308→              activeNoteId: wasActive ? id : state.activeNoteId,
   309→            }));
   310→            console.log('✅ Note restored (undo):', id);
   311→          }
   312→        );
   313→      },
   314→
   315→      duplicateNote: (id) => {
   316→        const original = get().notes[id];
   317→        if (!original) {
   318→          console.warn(`Note ${id} not found`);
   319→          return null;
   320→        }
   321→
   322→        const duplicate = createDefaultNote({
   323→          ...original,
   324→          title: `${original.title} (Copy)`,
   325→          isPinned: false, // Don't copy pin status
   326→        });
   327→
   328→        set((state) => ({
   329→          notes: {
   330→            ...state.notes,
   331→            [duplicate.id]: duplicate,
   332→          },
   333→        }));
   334→
   335→        console.log('✅ Note duplicated:', id, '→', duplicate.id);
   336→        return duplicate;
   337→      },
   338→
   339→      // Bulk operations
   340→      deleteNotes: (ids) => {
   341→        set((state) => {
   342→          const remainingNotes = { ...state.notes };
   343→          ids.forEach((id) => delete remainingNotes[id]);
   344→          return {
   345→            notes: remainingNotes,
   346→            activeNoteId: ids.includes(state.activeNoteId || '')
   347→              ? null
   348→              : state.activeNoteId,
   349→          };
   350→        });
   351→        console.log(`✅ Deleted ${ids.length} notes`);
   352→
   353→        // Delete associated images from IndexedDB (async, fire-and-forget)
   354→        import('../services/indexedDB').then(({ indexedDBService }) => {
   355→          ids.forEach((id) => {
   356→            indexedDBService.deleteNoteImages(id).catch((err) => {
   357→              console.error(`Failed to delete images for note ${id}:`, err);
   358→            });
   359→          });
   360→        });
   361→      },
   362→
   363→      moveNotesToFolder: (noteIds, folderId) => {
   364→        set((state) => {
   365→          const updatedNotes = { ...state.notes };
   366→          noteIds.forEach((id) => {
   367→            if (updatedNotes[id]) {
   368→              updatedNotes[id] = {
   369→                ...updatedNotes[id],
   370→                folderId,
   371→                updatedAt: new Date(),
   372→              };
   373→            }
   374→          });
   375→          return { notes: updatedNotes };
   376→        });
   377→        console.log(`✅ Moved ${noteIds.length} notes to folder:`, folderId);
   378→      },
   379→
   380→      archiveNotes: (noteIds) => {
   381→        set((state) => {
   382→          const updatedNotes = { ...state.notes };
   383→          noteIds.forEach((id) => {
   384→            if (updatedNotes[id]) {
   385→              updatedNotes[id] = {
   386→                ...updatedNotes[id],
   387→                isArchived: true,
   388→                updatedAt: new Date(),
   389→              };
   390→            }
   391→          });
   392→          return { notes: updatedNotes };
   393→        });
   394→        console.log(`✅ Archived ${noteIds.length} notes`);
   395→      },
   396→
   397→      unarchiveNotes: (noteIds) => {
   398→        set((state) => {
   399→          const updatedNotes = { ...state.notes };
   400→          noteIds.forEach((id) => {
   401→            if (updatedNotes[id]) {
   402→              updatedNotes[id] = {
   403→                ...updatedNotes[id],
   404→                isArchived: false,
   405→                updatedAt: new Date(),
   406→              };
   407→            }
   408→          });
   409→          return { notes: updatedNotes };
   410→        });
   411→        console.log(`✅ Unarchived ${noteIds.length} notes`);
   412→      },
   413→
   414→      // Queries
   415→      getAllNotes: () => {
   416→        const state = get();
   417→        const notes = Object.values(state.notes);
   418→        const filtered = filterNotes(notes, state.filter);
   419→        return sortNotes(filtered, state.sortConfig);
   420→      },
   421→
   422→      getNotesByFolder: (folderId) => {
   423→        const state = get();
   424→        const notes = Object.values(state.notes).filter(
   425→          (note) => note.folderId === folderId
   426→        );
   427→        const filtered = filterNotes(notes, state.filter);
   428→        return sortNotes(filtered, state.sortConfig);
   429→      },
   430→
   431→      getNotesBy: (predicate) => {
   432→        const notes = Object.values(get().notes).filter(predicate);
   433→        return sortNotes(notes, get().sortConfig);
   434→      },
   435→
   436→      searchNotes: (query) => {
   437→        if (!query.trim()) return [];
   438→
   439→        const lowerQuery = query.toLowerCase();
   440→        const notes = Object.values(get().notes).filter((note) => {
   441→          // Search in title, content text, and tags
   442→          return (
   443→            note.title.toLowerCase().includes(lowerQuery) ||
   444→            note.contentText.toLowerCase().includes(lowerQuery) ||
   445→            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
   446→          );
   447→        });
   448→
   449→        return sortNotes(notes, get().sortConfig);
   450→      },
   451→
   452→      // Pin/Archive
   453→      togglePin: (id) => {
   454→        const note = get().notes[id];
   455→        if (!note) return;
   456→
   457→        set((state) => ({
   458→          notes: {
   459→            ...state.notes,
   460→            [id]: {
   461→              ...note,
   462→              isPinned: !note.isPinned,
   463→              updatedAt: new Date(),
   464→            },
   465→          },
   466→        }));
   467→        console.log(`✅ Toggled pin for note: ${id} (${!note.isPinned})`);
   468→      },
   469→
   470→      toggleArchive: (id) => {
   471→        const note = get().notes[id];
   472→        if (!note) return;
   473→
   474→        set((state) => ({
   475→          notes: {
   476→            ...state.notes,
   477→            [id]: {
   478→              ...note,
   479→              isArchived: !note.isArchived,
   480→              updatedAt: new Date(),
   481→            },
   482→          },
   483→        }));
   484→        console.log(`✅ Toggled archive for note: ${id} (${!note.isArchived})`);
   485→      },
   486→
   487→      toggleFavorite: (id) => {
   488→        const note = get().notes[id];
   489→        if (!note) return;
   490→
   491→        set((state) => ({
   492→          notes: {
   493→            ...state.notes,
   494→            [id]: {
   495→              ...note,
   496→              isFavorite: !note.isFavorite,
   497→              updatedAt: new Date(),
   498→            },
   499→          },
   500→        }));
   501→        console.log(`✅ Toggled favorite for note: ${id} (${!note.isFavorite})`);
   502→      },
   503→
   504→      // Tags
   505→      addTag: (id, tag) => {
   506→        const note = get().notes[id];
   507→        if (!note) return;
   508→
   509→        // Don't add duplicate tags
   510→        if (note.tags.includes(tag)) return;
   511→
   512→        // Check max tags limit
   513→        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
   514→          console.warn(`Max tags (${NOTE_CONSTANTS.MAX_TAGS}) reached`);
   515→          return;
   516→        }
   517→
   518→        set((state) => ({
   519→          notes: {
   520→            ...state.notes,
   521→            [id]: {
   522→              ...note,
   523→              tags: [...note.tags, tag],
   524→              updatedAt: new Date(),
   525→            },
   526→          },
   527→        }));
   528→        console.log(`✅ Added tag "${tag}" to note: ${id}`);
   529→      },
   530→
   531→      removeTag: (id, tag) => {
   532→        const note = get().notes[id];
   533→        if (!note) return;
   534→
   535→        set((state) => ({
   536→          notes: {
   537→            ...state.notes,
   538→            [id]: {
   539→              ...note,
   540→              tags: note.tags.filter((t) => t !== tag),
   541→              updatedAt: new Date(),
   542→            },
   543→          },
   544→        }));
   545→        console.log(`✅ Removed tag "${tag}" from note: ${id}`);
   546→      },
   547→
   548→      getAllTags: () => {
   549→        const notes = Object.values(get().notes);
   550→        const tagSet = new Set<string>();
   551→        notes.forEach((note) => {
   552→          note.tags.forEach((tag) => tagSet.add(tag));
   553→        });
   554→        return Array.from(tagSet).sort();
   555→      },
   556→
   557→      // UI state
   558→      setActiveNote: (id) => {
   559→        set({ activeNoteId: id });
   560→        console.log('✅ Active note set:', id);
   561→      },
   562→
   563→      setSortConfig: (config) => {
   564→        set({ sortConfig: config });
   565→        console.log('✅ Sort config updated:', config);
   566→      },
   567→
   568→      setFilter: (filter) => {
   569→        set({ filter });
   570→        console.log('✅ Filter updated:', filter);
   571→      },
   572→
   573→      // Utility
   574→      getNoteCount: () => {
   575→        return Object.keys(get().notes).length;
   576→      },
   577→
   578→      getNotesInFolder: (folderId) => {
   579→        return Object.values(get().notes).filter(
   580→          (note) => note.folderId === folderId
   581→        );
   582→      },
   583→
   584→      exportNotes: () => {
   585→        return Object.values(get().notes);
   586→      },
   587→
   588→      importNotes: (notes, merge) => {
   589→        if (!merge) {
   590→          // Replace all notes
   591→          set({
   592→            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   593→            activeNoteId: null,
   594→          });
   595→          console.log(`✅ Imported ${notes.length} notes (replace mode)`);
   596→        } else {
   597→          // Merge with existing notes
   598→          set((state) => {
   599→            const updatedNotes = { ...state.notes };
   600→            notes.forEach((note) => {
   601→              updatedNotes[note.id] = note;
   602→            });
   603→            return { notes: updatedNotes };
   604→          });
   605→          console.log(`✅ Imported ${notes.length} notes (merge mode)`);
   606→        }
   607→      },
   608→
   609→      clearAllNotes: () => {
   610→        set({ notes: {}, activeNoteId: null });
   611→        console.log('✅ All notes cleared');
   612→      },
   613→
   614→      // ==================== BACKLINKS (Phase 4) ====================
   615→
   616→      getBacklinks: (noteId: string) => {
   617→        const state = get();
   618→        const note = state.notes[noteId];
   619→        if (!note) return [];
   620→
   621→        return getBacklinksUtil(noteId, note.title, state.notes);
   622→      },
   623→
   624→      updateLinkedNotes: (noteId: string, content: string) => {
   625→        const state = get();
   626→        const linkTitles = extractWikiLinks(content);
   627→        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);
   628→
   629→        set((currentState) => {
   630→          const note = currentState.notes[noteId];
   631→          if (!note) return currentState;
   632→
   633→          return {
   634→            notes: {
   635→              ...currentState.notes,
   636→              [noteId]: {
   637→                ...note,
   638→                linkedNotes: linkedNoteIds,
   639→              },
   640→            },
   641→          };
   642→        });
   643→      },
   644→
   645→      // ==================== TEMPLATES (Phase 4) ====================
   646→
   647→      getNoteTemplates: () => {
   648→        return DEFAULT_NOTE_TEMPLATES;
   649→      },
   650→
   651→      createNoteFromTemplate: (templateId: string) => {
   652→        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
   653→        if (!template) return null;
   654→
   655→        const newNote = createDefaultNote({
   656→          title: template.name,
   657→          contentText: template.description,
   658→          tags: template.defaultTags || [],
   659→          icon: template.icon,
   660→        });
   661→
   662→        set((state) => ({
   663→          notes: {
   664→            ...state.notes,
   665→            [newNote.id]: newNote,
   666→          },
   667→          activeNoteId: newNote.id,
   668→        }));
   669→
   670→        console.log(`✅ Created note from template: ${template.name}`);
   671→        return newNote;
   672→      },
   673→    }),
   674→    {
   675→      name: 'notes', // IndexedDB key
   676→      storage: createJSONStorage(() => createSyncedStorage()),
   677→      partialize: (state) => ({
   678→        // Only persist notes, not UI state
   679→        notes: state.notes,
   680→      }),
   681→      // Handle date serialization
   682→      onRehydrateStorage: () => (state) => {
   683→        console.log('🔄 Notes store rehydrating...', state);
   684→        if (state) {
   685→          try {
   686→            // Ensure notes object exists and is valid
   687→            if (state.notes && typeof state.notes === 'object') {
   688→              // Convert date strings back to Date objects
   689→              Object.values(state.notes).forEach((note) => {
   690→                if (typeof note.createdAt === 'string') {
   691→                  note.createdAt = new Date(note.createdAt);
   692→                }
   693→                if (typeof note.updatedAt === 'string') {
   694→                  note.updatedAt = new Date(note.updatedAt);
   695→                }
   696→              });
   697→            } else {
   698→              console.warn('⚠️ Corrupted notes data detected, resetting to empty');
   699→              state.notes = {};
   700→            }
   701→          } catch (err) {
   702→            console.error('❌ Error during notes store rehydration:', err);
   703→            // Reset to safe defaults
   704→            state.notes = {};
   705→            state.activeNoteId = null;
   706→          }
   707→        }
   708→        console.log('✅ Notes store rehydrated', state);
   709→      },
   710→    }
   711→  )
   712→);
   713→
   714→/**
   715→ * Selector hooks for optimized re-renders
   716→ */
   717→export const useActiveNote = () =>
   718→  useNotesStore((state) => {
   719→    const activeId = state.activeNoteId;
   720→    return activeId ? state.notes[activeId] : null;
   721→  });
   722→
   723→export const useNotesByFolder = (folderId: string | null) =>
   724→  useNotesStore((state) => state.getNotesByFolder(folderId));
   725→
   726→export const useAllTags = () => useNotesStore((state) => state.getAllTags());
