    86→  deleteTask: (id: string) => void;
    87→  moveTask: (id: string, newStatus: TaskStatus) => void;
    88→  getTasksByStatus: (status: TaskStatus) => Task[];
    89→
    90→  // Phase 4: Column management
    91→  addColumn: (column: Omit<KanbanColumn, 'id' | 'order'>) => void;
    92→  updateColumn: (id: string, updates: Partial<KanbanColumn>) => void;
    93→  deleteColumn: (id: string) => void;
    94→  reorderColumns: (columnIds: string[]) => void;
    95→  replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => void;
    96→
    97→  // Phase 4: Checklist management
    98→  addChecklistItem: (taskId: string, text: string) => void;
    99→  updateChecklistItem: (taskId: string, itemId: string, updates: Partial<ChecklistItem>) => void;
   100→  deleteChecklistItem: (taskId: string, itemId: string) => void;
   101→  toggleChecklistItem: (taskId: string, itemId: string) => void;
   102→  reorderChecklistItems: (taskId: string, itemIds: string[]) => void;
   103→
   104→  // Phase 4: Comment management
   105→  addComment: (taskId: string, text: string) => void;
   106→  updateComment: (taskId: string, commentId: string, text: string) => void;
   107→  deleteComment: (taskId: string, commentId: string) => void;
   108→
   109→  // Phase 4: Activity log (auto-tracked)
   110→  logActivity: (taskId: string, entry: Omit<ActivityLogEntry, 'id' | 'timestamp'>) => void;
   111→
   112→  // Phase 4: Bulk actions
   113→  bulkUpdateStatus: (taskIds: string[], newStatus: TaskStatus) => void;
   114→  bulkUpdatePriority: (taskIds: string[], newPriority: TaskPriority) => void;
   115→  bulkDeleteTasks: (taskIds: string[]) => void;
   116→
   117→  // Phase 5: Subtask management
   118→  addSubtask: (taskId: string, subtaskData: Omit<Subtask, 'id' | 'parentTaskId' | 'createdAt' | 'order'>) => void;
   119→  updateSubtask: (taskId: string, subtaskId: string, updates: Partial<Subtask>) => void;
   120→  deleteSubtask: (taskId: string, subtaskId: string) => void;
   121→  toggleSubtask: (taskId: string, subtaskId: string) => void;
   122→  reorderSubtasks: (taskId: string, subtaskIds: string[]) => void;
   123→
   124→  // Phase 5: Dependency management
   125→  addDependency: (sourceTaskId: string, targetTaskId: string) => void;
   126→  removeDependency: (dependencyId: string) => void;
   127→  getBlockers: (taskId: string) => Task[];
   128→  getBlocked: (taskId: string) => Task[];
   129→
   130→  // Phase A: Archive management
   131→  archiveTask: (id: string) => void;
   132→  restoreTask: (id: string) => void;
   133→  deleteArchivedTask: (id: string) => void;
   134→  getArchivedTasks: () => Task[];
   135→  autoArchiveCompletedTasks: () => void;
   136→
   137→  // Phase B: Time tracking
   138→  startTimer: (taskId: string) => void;
   139→  stopTimer: (taskId: string) => void;
   140→  updateTimeEstimate: (taskId: string, hours: number) => void;
   141→
   142→  // Phase B: Custom fields
   143→  updateEffort: (taskId: string, effort: import('../types').EffortEstimate | undefined) => void;
   144→  updateCustomStatus: (taskId: string, customStatus: import('../types').CustomStatus | undefined) => void;
   145→
   146→  // UI Preferences
