   158→
   159→export const useKanbanStore = create<KanbanStore>()(
   160→  persist(
   161→    (set, get) => ({
   162→      // Initial state
   163→      tasks: [],
   164→      columns: DEFAULT_COLUMNS,
   165→      dependencies: [], // Phase 5: Task dependencies
   166→      archivedTasks: [], // Phase A: Archived tasks
   167→      nextCardNumber: 1, // Phase A: Auto-incrementing card number counter
   168→      visibleColumns: 5, // UI: Number of columns visible before scrolling (default: 5)
   169→      undoHistory: [], // Undo system: stores last 5 actions
   170→
   171→      // ==================== TASK ACTIONS ====================
   172→
   173→      addTask: (taskData) => {
   174→        const currentNumber = get().nextCardNumber || 1;
   175→
   176→        const newTask: Task = {
   177→          ...taskData,
   178→          id: Date.now().toString(),
   179→          created: new Date().toISOString(),
   180→          cardNumber: currentNumber, // Phase A: Assign auto-incrementing card number
   181→          checklist: [],
   182→          comments: [],
   183→          activityLog: [],
   184→        };
   185→
   186→        set((state) => ({
   187→          tasks: [...state.tasks, newTask],
   188→          nextCardNumber: currentNumber + 1, // Increment counter
   189→        }));
   190→
   191→        // Log creation
   192→        get().logActivity(newTask.id, {
   193→          action: 'created',
   194→        });
   195→      },
   196→
   197→      updateTask: (id, updates) => {
   198→        const oldTask = get().tasks.find((t) => t.id === id);
   199→        if (!oldTask) return;
   200→
   201→        set((state) => ({
   202→          tasks: state.tasks.map((task) =>
   203→            task.id === id ? { ...task, ...updates } : task
   204→          ),
   205→        }));
   206→
   207→        // Log updates (track specific fields)
   208→        Object.keys(updates).forEach((field) => {
   209→          if (field !== 'activityLog') { // Don't log the log itself
   210→            get().logActivity(id, {
   211→              action: 'updated',
   212→              field,
   213→              oldValue: String(oldTask[field as keyof Task] ?? ''),
   214→              newValue: String(updates[field as keyof Task] ?? ''),
   215→            });
   216→          }
   217→        });
   218→      },
   219→
   220→      deleteTask: (id) =>
   221→        set((state) => ({
   222→          tasks: state.tasks.filter((task) => task.id !== id),
   223→        })),
   224→
   225→      moveTask: (id, newStatus) => {
   226→        const oldTask = get().tasks.find((t) => t.id === id);
   227→        if (!oldTask) return;
   228→
   229→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   230→        if (newStatus === 'done') {
   231→          const blockers = get().getBlockers(id);
   232→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   233→
   234→          if (incompleteBlockers.length > 0) {
   235→            console.warn(
   236→              `Cannot complete task "${oldTask.title}": Blocked by ${incompleteBlockers.length} incomplete task(s)`
   237→            );
   238→            // TODO: Show toast notification in UI
   239→            return; // Prevent move
   240→          }
   241→        }
   242→
   243→        // PHASE A: Track when task is completed (for auto-archive)
   244→        const updates: Partial<Task> = { status: newStatus };
   245→        if (newStatus === 'done' && oldTask.status !== 'done') {
   246→          updates.lastCompletedAt = new Date().toISOString();
   247→        }
   248→
   249→        set((state) => ({
   250→          tasks: state.tasks.map((task) =>
   251→            task.id === id ? { ...task, ...updates } : task
   252→          ),
   253→        }));
   254→
   255→        // Log move
   256→        get().logActivity(id, {
   257→          action: 'moved',
   258→          field: 'status',
   259→          oldValue: oldTask.status,
   260→          newValue: newStatus,
   261→        });
   262→      },
   263→
   264→      getTasksByStatus: (status) => {
   265→        return get().tasks.filter((task) => task.status === status);
   266→      },
   267→
   268→      // ==================== COLUMN ACTIONS ====================
   269→
   270→      addColumn: (columnData) => {
   271→        const columns = get().columns;
   272→        const newColumn: KanbanColumn = {
   273→          ...columnData,
   274→          id: `col-${Date.now()}`,
   275→          order: columns.length,
   276→        };
   277→
   278→        set((state) => ({
   279→          columns: [...state.columns, newColumn],
   280→        }));
   281→      },
   282→
   283→      updateColumn: (id, updates) => {
   284→        set((state) => ({
   285→          columns: state.columns.map((col) =>
   286→            col.id === id ? { ...col, ...updates } : col
   287→          ),
   288→        }));
   289→      },
   290→
   291→      deleteColumn: (id) => {
   292→        const state = get();
   293→        const columnToDelete = state.columns.find(col => col.id === id);
   294→
   295→        if (!columnToDelete) {
   296→          console.warn(`deleteColumn: Column with id '${id}' not found`);
   297→          return;
   298→        }
   299→
   300→        // Save undo entry BEFORE making changes
   301→        get().addToUndoHistory({
   302→          action: 'deleteColumn',
   303→          description: `Deleted column '${columnToDelete.title}'`,
   304→          previousState: {
   305→            columns: state.columns,
   306→            tasks: state.tasks,
   307→          },
   308→        });
   309→
   310→        // Find first remaining column (fallback, not hardcoded 'backlog')
   311→        const firstRemainingColumn = state.columns.find(col => col.id !== id);
   312→
   313→        if (!firstRemainingColumn) {
   314→          console.error('deleteColumn: Cannot delete last column');
   315→          return;
   316→        }
   317→
   318→        // Move all tasks from deleted column to first remaining column
   319→        set((state) => ({
   320→          columns: state.columns.filter((col) => col.id !== id),
   321→          tasks: state.tasks.map((task) =>
   322→            task.status === id as TaskStatus
   323→              ? { ...task, status: firstRemainingColumn.id as TaskStatus }
   324→              : task
   325→          ),
   326→        }));
   327→      },
   328→
   329→      reorderColumns: (columnIds) => {
   330→        const columns = get().columns;
   331→        const reordered = columnIds
   332→          .map((id) => columns.find((col) => col.id === id))
   333→          .filter((col): col is KanbanColumn => col !== undefined)
   334→          .map((col, index) => ({ ...col, order: index }));
   335→
   336→        set({ columns: reordered });
   337→      },
   338→
   339→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   340→        const state = get();
   341→
   342→        // Save undo entry BEFORE making changes
   343→        get().addToUndoHistory({
   344→          action: 'replaceAllColumns',
   345→          description: `Applied template`,
   346→          previousState: {
   347→            columns: state.columns,
   348→            tasks: state.tasks,
   349→          },
   350→        });
   351→
   352→        // Generate new columns with fresh IDs and correct order
   353→        const columns: KanbanColumn[] = newColumns.map((col, index) => ({
   354→          ...col,
   355→          id: `col-${Date.now()}-${index}`,
   356→          order: index,
   357→        }));
   358→
   359→        if (columns.length === 0) {
   360→          console.error('replaceAllColumns: No columns provided');
   361→          return;
   362→        }
   363→
   364→        // Smart mapping: Try to preserve task positions based on column titles
   365→        const tasks = state.tasks.map(task => {
   366→          const oldColumn = state.columns.find(c => c.id === task.status);
   367→          if (!oldColumn) {
   368→            // Task has invalid status, move to first column
   369→            return { ...task, status: columns[0].id as TaskStatus };
   370→          }
   371→
   372→          // Try exact match first (case-insensitive)
   373→          let newColumn = columns.find(c =>
   374→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   375→          );
   376→
   377→          // If no exact match, try partial match (contains)
   378→          if (!newColumn) {
   379→            newColumn = columns.find(c =>
   380→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   381→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   382→            );
   383→          }
   384→
   385→          // Fallback: first column
   386→          if (!newColumn) {
   387→            newColumn = columns[0];
   388→          }
   389→
   390→          return { ...task, status: newColumn.id as TaskStatus };
   391→        });
   392→
   393→        set({ columns, tasks });
   394→      },
   395→
   396→      // ==================== CHECKLIST ACTIONS ====================
   397→
   398→      addChecklistItem: (taskId, text) => {
   399→        const task = get().tasks.find((t) => t.id === taskId);
   400→        if (!task) return;
   401→
   402→        const newItem: ChecklistItem = {
