   421→          newValue: `Added: ${text}`,
   422→        });
   423→      },
   424→
   425→      updateChecklistItem: (taskId, itemId, updates) => {
   426→        set((state) => ({
   427→          tasks: state.tasks.map((t) =>
   428→            t.id === taskId
   429→              ? {
   430→                  ...t,
   431→                  checklist: (t.checklist || []).map((item) =>
   432→                    item.id === itemId ? { ...item, ...updates } : item
   433→                  ),
   434→                }
   435→              : t
   436→          ),
   437→        }));
   438→      },
   439→
   440→      deleteChecklistItem: (taskId, itemId) => {
   441→        const task = get().tasks.find((t) => t.id === taskId);
   442→        if (!task) return;
   443→
   444→        const item = task.checklist?.find((i) => i.id === itemId);
   445→        if (!item) return;
   446→
   447→        set((state) => ({
   448→          tasks: state.tasks.map((t) =>
   449→            t.id === taskId
   450→              ? {
   451→                  ...t,
   452→                  checklist: (t.checklist || []).filter((i) => i.id !== itemId),
   453→                }
   454→              : t
   455→          ),
   456→        }));
   457→
   458→        // Log deletion
   459→        get().logActivity(taskId, {
   460→          action: 'checklist_updated',
   461→          oldValue: `Removed: ${item.text}`,
   462→        });
   463→      },
   464→
   465→      toggleChecklistItem: (taskId, itemId) => {
   466→        const task = get().tasks.find((t) => t.id === taskId);
   467→        if (!task) return;
   468→
   469→        const item = task.checklist?.find((i) => i.id === itemId);
   470→        if (!item) return;
   471→
   472→        set((state) => ({
   473→          tasks: state.tasks.map((t) =>
   474→            t.id === taskId
   475→              ? {
   476→                  ...t,
   477→                  checklist: (t.checklist || []).map((i) =>
   478→                    i.id === itemId ? { ...i, completed: !i.completed } : i
   479→                  ),
   480→                }
   481→              : t
   482→          ),
   483→        }));
   484→
   485→        // Log toggle
   486→        get().logActivity(taskId, {
   487→          action: 'checklist_updated',
   488→          newValue: `${!item.completed ? 'Completed' : 'Unchecked'}: ${item.text}`,
   489→        });
   490→      },
   491→
   492→      reorderChecklistItems: (taskId, itemIds) => {
