   678→        set((state) => ({
   679→          tasks: state.tasks.map((task) =>
   680→            taskIds.includes(task.id)
   681→              ? { ...task, priority: newPriority }
   682→              : task
   683→          ),
   684→        }));
   685→
   686→        // Log activity for each task
   687→        taskIds.forEach(taskId => {
   688→          const task = state.tasks.find(t => t.id === taskId);
   689→          if (task) {
   690→            get().logActivity(taskId, {
   691→              action: 'updated',
   692→              field: 'priority',
   693→              oldValue: task.priority,
   694→              newValue: newPriority,
   695→            });
   696→          }
   697→        });
   698→      },
   699→
   700→      bulkDeleteTasks: (taskIds) => {
   701→        const state = get();
   702→
   703→        // Save undo state
   704→        get().addToUndoHistory({
   705→          action: 'bulkDelete',
   706→          description: `Deleted ${taskIds.length} tasks`,
   707→          previousState: {
