   753→              return {
   754→                ...task,
   755→                subtasks: task.subtasks.map((subtask) =>
   756→                  subtask.id === subtaskId ? { ...subtask, ...updates } : subtask
   757→                ),
   758→              };
   759→            }
   760→            return task;
   761→          }),
   762→        }));
   763→
   764→        // Log activity
   765→        get().logActivity(taskId, {
   766→          action: 'updated',
   767→          field: 'subtask',
   768→          newValue: JSON.stringify(updates),
   769→        });
   770→      },
   771→
   772→      deleteSubtask: (taskId, subtaskId) => {
   773→        const task = get().tasks.find((t) => t.id === taskId);
   774→        const subtask = task?.subtasks?.find((s) => s.id === subtaskId);
   775→
   776→        set((state) => ({
   777→          tasks: state.tasks.map((task) => {
   778→            if (task.id === taskId && task.subtasks) {
   779→              return {
   780→                ...task,
   781→                subtasks: task.subtasks.filter((s) => s.id !== subtaskId),
   782→              };
   783→            }
   784→            return task;
   785→          }),
   786→        }));
   787→
   788→        // Log activity
   789→        if (subtask) {
