   861→      // ==================== PHASE 5: DEPENDENCY ACTIONS ====================
   862→
   863→      addDependency: (sourceTaskId, targetTaskId) => {
   864→        // Prevent self-dependency
   865→        if (sourceTaskId === targetTaskId) {
   866→          console.error('Task cannot depend on itself');
   867→          return;
   868→        }
   869→
   870→        // Check for circular dependency
   871→        const dependencies = get().dependencies || [];
   872→        const wouldCreateCycle = (source: string, target: string): boolean => {
   873→          if (source === target) return true;
   874→          const childDeps = dependencies.filter((d) => d.sourceTaskId === target);
   875→          return childDeps.some((d) => wouldCreateCycle(source, d.targetTaskId));
   876→        };
   877→
   878→        if (wouldCreateCycle(sourceTaskId, targetTaskId)) {
