   905→        });
   906→      },
   907→
   908→      removeDependency: (dependencyId) => {
   909→        const dependency = get().dependencies?.find((d) => d.id === dependencyId);
   910→
   911→        set((state) => ({
   912→          dependencies: (state.dependencies || []).filter((d) => d.id !== dependencyId),
   913→        }));
   914→
   915→        // Log activity
   916→        if (dependency) {
   917→          get().logActivity(dependency.sourceTaskId, {
   918→            action: 'updated',
   919→            field: 'dependency',
   920→            oldValue: `Blocks task ${dependency.targetTaskId}`,
   921→          });
   922→
   923→          get().logActivity(dependency.targetTaskId, {
   924→            action: 'updated',
   925→            field: 'dependency',
   926→            oldValue: `Blocked by task ${dependency.sourceTaskId}`,
   927→          });
   928→        }
   929→      },
   930→
   931→      getBlockers: (taskId) => {
   932→        const dependencies = get().dependencies || [];
   933→        const blockerIds = dependencies
   934→          .filter((d) => d.targetTaskId === taskId)
   935→          .map((d) => d.sourceTaskId);
   936→
   937→        return get().tasks.filter((t) => blockerIds.includes(t.id));
   938→      },
   939→
   940→      getBlocked: (taskId) => {
   941→        const dependencies = get().dependencies || [];
   942→        const blockedIds = dependencies
   943→          .filter((d) => d.sourceTaskId === taskId)
   944→          .map((d) => d.targetTaskId);
   945→
   946→        return get().tasks.filter((t) => blockedIds.includes(t.id));
   947→      },
   948→
   949→      // ==================== PHASE A: ARCHIVE ACTIONS ====================
   950→
   951→      archiveTask: (id) => {
   952→        const task = get().tasks.find((t) => t.id === id);
   953→        if (!task) return;
   954→
   955→        const archivedTask: Task = {
   956→          ...task,
   957→          archivedAt: new Date().toISOString(),
   958→        };
   959→
   960→        set((state) => ({
