   963→        }));
   964→
   965→        // Log archive action
   966→        get().logActivity(id, {
   967→          action: 'updated',
   968→          field: 'archived',
   969→          newValue: 'true',
   970→        });
   971→      },
   972→
   973→      restoreTask: (id) => {
