    31→
    32→/**
    33→ * Convert ArrayBuffer to hex string
    34→ */
    35→function arrayBufferToHex(buffer: ArrayBuffer): string {
    36→  return Array.from(new Uint8Array(buffer))
    37→    .map(b => b.toString(16).padStart(2, '0'))
    38→    .join('');
    39→}
    40→
    41→/**
    42→ * Convert hex string to ArrayBuffer
    43→ */
    44→function hexToArrayBuffer(hex: string): ArrayBuffer {
    45→  const bytes = new Uint8Array(hex.length / 2);
    46→  for (let i = 0; i < hex.length; i += 2) {
    47→    bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
    48→  }
    49→  return bytes.buffer;
    50→}
    51→
    52→/**
    53→ * Convert ArrayBuffer to Base64 string
    54→ */
    55→function arrayBufferToBase64(buffer: ArrayBuffer): string {
    56→  const bytes = new Uint8Array(buffer);
    57→  let binary = '';
    58→  for (let i = 0; i < bytes.length; i++) {
    59→    binary += String.fromCharCode(bytes[i]);
    60→  }
