     1→/**
     2→ * IndexedDB Service - Unlimited Local Storage
     3→ *
     4→ * Provides a localStorage-like interface with IndexedDB backend
     5→ * Benefits:
     6→ * - 50GB+ storage capacity (vs 5-10MB localStorage)
     7→ * - Handles large data (images, rich text, etc.)
     8→ * - Async operations for better performance
     9→ * - Automatic versioning and migrations
    10→ */
    11→
    12→const DB_NAME = 'neuman-brain-db';
    13→const DB_VERSION = 1;
    14→const STORE_NAME = 'brain-data';
    15→
    16→interface DBConnection {
    17→  db: IDBDatabase | null;
    18→  isReady: boolean;
    19→}
    20→
    21→class IndexedDBService {
    22→  private connection: DBConnection = {
    23→    db: null,
    24→    isReady: false,
    25→  };
    26→
    27→  /**
    28→   * Initialize IndexedDB connection
    29→   */
    30→  async init(): Promise<void> {
    31→    if (this.connection.isReady) {
    32→      return;
    33→    }
    34→
    35→    return new Promise((resolve, reject) => {
    36→      const request = indexedDB.open(DB_NAME, DB_VERSION);
