    95→    return new Promise((resolve, reject) => {
    96→      if (!this.connection.db) {
    97→        reject(new Error('IndexedDB not initialized'));
    98→        return;
    99→      }
   100→
   101→      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
   102→      const store = transaction.objectStore(STORE_NAME);
