   141→  }
   142→
   143→  /**
   144→   * Get all keys from IndexedDB
   145→   */
   146→  async getAllKeys(): Promise<string[]> {
   147→    await this.init();
   148→
   149→    return new Promise((resolve, reject) => {
   150→      if (!this.connection.db) {
   151→        reject(new Error('IndexedDB not initialized'));
   152→        return;
   153→      }
   154→
   155→      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
