   216→
   217→  /**
   218→   * Batch write multiple items in a single transaction (50-100x faster than individual writes)
   219→   * @param items - Object with key-value pairs to write
   220→   * @returns Promise that resolves when all items are written
   221→   */
   222→  async setItemsBatch(items: Record<string, string>): Promise<void> {
   223→    await this.init();
   224→
   225→    return new Promise((resolve, reject) => {
   226→      const transaction = this.connection.db!.transaction(STORE_NAME, 'readwrite');
   227→      const store = transaction.objectStore(STORE_NAME);
   228→
   229→      // Write all items in a single transaction
   230→      Object.entries(items).forEach(([key, value]) => {
   231→        store.put(value, key);
   232→      });
   233→
   234→      transaction.oncomplete = () => {
   235→        console.log(`✅ Batch wrote ${Object.keys(items).length} items to IndexedDB`);
   236→        resolve();
   237→      };
   238→
   239→      transaction.onerror = () => {
   240→        console.error('Failed to batch write items:', transaction.error);
   241→        reject(transaction.error);
   242→      };
   243→    });
   244→  }
   245→
   246→  /**
   247→   * Batch read multiple items in a single transaction
   248→   * @param keys - Array of keys to read
   249→   * @returns Promise with object containing key-value pairs (missing keys are omitted)
   250→   */
   251→  async getItemsBatch(keys: string[]): Promise<Record<string, string>> {
   252→    await this.init();
   253→
   254→    return new Promise((resolve, reject) => {
   255→      const transaction = this.connection.db!.transaction(STORE_NAME, 'readonly');
   256→      const store = transaction.objectStore(STORE_NAME);
   257→      const results: Record<string, string> = {};
   258→      let pending = keys.length;
   259→
   260→      if (pending === 0) {
   261→        resolve({});
   262→        return;
   263→      }
   264→
   265→      keys.forEach((key) => {
   266→        const request = store.get(key);
   267→        request.onsuccess = () => {
   268→          if (request.result !== undefined) {
   269→            results[key] = request.result;
   270→          }
