   274→          }
   275→        };
   276→      });
   277→
   278→      transaction.onerror = () => {
   279→        console.error('Failed to batch read items:', transaction.error);
   280→        reject(transaction.error);
   281→      };
   282→    });
   283→  }
   284→
   285→  /**
