   300→      const quota = estimate.quota || 0;
   301→      const percentUsed = quota > 0 ? (usage / quota) * 100 : 0;
   302→      const available = quota - usage;
   303→
   304→      return {
   305→        usage,
   306→        quota,
   307→        percentUsed,
   308→        available,
   309→        usageFormatted: this.formatBytes(usage),
   310→        quotaFormatted: this.formatBytes(quota),
   311→        availableFormatted: this.formatBytes(available),
   312→      };
   313→    }
   314→
   315→    // Fallback for browsers without Storage API
   316→    return {
   317→      usage: 0,
   318→      quota: 0,
   319→      percentUsed: 0,
   320→      available: 0,
   321→      usageFormatted: '0 Bytes',
   322→      quotaFormatted: '0 Bytes',
   323→      availableFormatted: '0 Bytes',
   324→    };
   325→  }
   326→
   327→  /**
   328→   * Format bytes to human-readable string
   329→   */
   330→  formatBytes(bytes: number): string {
   331→    if (bytes === 0) return '0 Bytes';
   332→    const k = 1024;
   333→    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
   334→    const i = Math.floor(Math.log(bytes) / Math.log(k));
