    19→ *     }
    20→ *   )
    21→ */
    22→
    23→export const createSyncedStorage = (): StateStorage => {
    24→  return {
    25→    getItem: async (name: string): Promise<string | null> => {
    26→      try {
    27→        // Try IndexedDB first
    28→        if (indexedDBService.isSupported()) {
    29→          const stored = await indexedDBService.getItem(name);
    30→          if (stored) {
    31→            return stored;
    32→          }
    33→        }
    34→
    35→        // Fallback to localStorage
    36→        const stored = localStorage.getItem(name);
    37→        if (stored) {
    38→          // Migrate to IndexedDB if available
    39→          if (indexedDBService.isSupported()) {
    40→            await indexedDBService.setItem(name, stored);
    41→          }
    42→          return stored;
    43→        }
    44→
    45→        return null;
    46→      } catch (error) {
    47→        console.error(`Failed to load ${name}:`, error);
    48→        return null;
    49→      }
    50→    },
    51→
    52→    setItem: async (name: string, value: string): Promise<void> => {
    53→      try {
    54→        // Indicate saving in progress
    55→        saveStatusActions.setSaving();
    56→
    57→        // Save to IndexedDB (primary storage)
    58→        if (indexedDBService.isSupported()) {
    59→          await indexedDBService.setItem(name, value);
    60→        } else {
    61→          // Fallback to localStorage if IndexedDB unavailable
    62→          localStorage.setItem(name, value);
    63→        }
    64→
    65→        // Mark as successfully saved
    66→        saveStatusActions.setSaved();
    67→      } catch (error) {
    68→        console.error(`Failed to save ${name}:`, error);
    69→        saveStatusActions.setError(`Failed to save ${name}`);
