   270→      pauseTimer: () => {
   271→        const { activeEntry } = get();
   272→        if (!activeEntry) return;
   273→
   274→        const now = new Date().toISOString();
   275→        const pausedEntry = {
   276→          ...activeEntry,
   277→          pausedAt: now,
   278→          isPaused: true,
   279→          updatedAt: now
   280→        };
   281→
   282→        set({ activeEntry: pausedEntry });
   283→        localStorage.setItem('activeTimer', JSON.stringify(pausedEntry));
   284→      },
   285→
   286→      resumeTimer: () => {
   287→        const { activeEntry } = get();
   288→        if (!activeEntry || !activeEntry.isPaused) return;
   289→
   290→        const now = new Date().toISOString();
   291→        const pausedDuration = activeEntry.pausedAt
   292→          ? new Date(now).getTime() - new Date(activeEntry.pausedAt).getTime()
   293→          : 0;
   294→
   295→        const resumedEntry = {
   296→          ...activeEntry,
   297→          startTime: new Date(
   298→            new Date(activeEntry.startTime).getTime() + pausedDuration
   299→          ).toISOString(),
   300→          isPaused: false,
   301→          pausedAt: undefined,
   302→          updatedAt: now
   303→        };
   304→
   305→        set({ activeEntry: resumedEntry });
   306→        localStorage.setItem('activeTimer', JSON.stringify(resumedEntry));
   307→      },
   308→
   309→      stopTimer: async () => {
   310→        const { activeEntry, entries } = get();
   311→        if (!activeEntry) return;
   312→
   313→        const endTime = new Date().toISOString();
   314→        const duration = Math.floor(
   315→          (new Date(endTime).getTime() - new Date(activeEntry.startTime).getTime()) / 1000
   316→        );
   317→
   318→        const completedEntry: TimeEntry = {
   319→          ...activeEntry,
   320→          endTime,
   321→          duration,
   322→          updatedAt: new Date().toISOString()
   323→        };
   324→
   325→        // Save to IndexedDB
   326→        await timeTrackingDb.addEntry(completedEntry);
   327→
   328→        // Update state
   329→        set({
   330→          activeEntry: null,
   331→          entries: [completedEntry, ...entries]
