   525→
   526→        // Calculate date range based on filter
   527→        if (filters?.dateRange) {
   528→          const now = new Date();
   529→          switch (filters.dateRange) {
   530→            case 'today':
   531→              startDate = new Date(now.setHours(0, 0, 0, 0));
   532→              endDate = new Date(now.setHours(23, 59, 59, 999));
   533→              break;
   534→            case 'yesterday':
   535→              startDate = new Date(now.setDate(now.getDate() - 1));
   536→              startDate.setHours(0, 0, 0, 0);
   537→              endDate = new Date(startDate);
   538→              endDate.setHours(23, 59, 59, 999);
   539→              break;
   540→            case 'last7days':
   541→              startDate = new Date(now.setDate(now.getDate() - 7));
   542→              startDate.setHours(0, 0, 0, 0);
   543→              endDate = new Date();
   544→              break;
   545→            case 'last30days':
   546→              startDate = new Date(now.setDate(now.getDate() - 30));
   547→              startDate.setHours(0, 0, 0, 0);
   548→              endDate = new Date();
   549→              break;
   550→            case 'custom':
   551→              if (filters.startDate) startDate = new Date(filters.startDate);
   552→              if (filters.endDate) endDate = new Date(filters.endDate);
   553→              break;
   554→          }
   555→        }
   556→
   557→        const entries = await timeTrackingDb.getEntries({
   558→          startDate,
   559→          endDate,
   560→          projectId: filters?.projectIds?.[0], // For now, single project filter
   561→          searchQuery: filters?.searchQuery
   562→        });
   563→
   564→        set({ entries });
   565→      },
