   638→      getTodayTotal: async () => {
   639→        const now = new Date();
   640→        const startOfDay = new Date(now);
   641→        startOfDay.setHours(0, 0, 0, 0);
   642→        const endOfDay = new Date(now);
   643→        endOfDay.setHours(23, 59, 59, 999);
   644→
   645→        const entries = await timeTrackingDb.getEntriesByDateRange(startOfDay, endOfDay);
   646→        const total = entries.reduce((sum, entry) => sum + entry.duration, 0);
   647→
   648→        // Add active timer duration if running
