   659→      getDailySummary: async (days) => {
   660→        const now = new Date();
   661→        const startDate = new Date(now);
   662→        startDate.setDate(startDate.getDate() - days + 1);
   663→        startDate.setHours(0, 0, 0, 0);
   664→
   665→        const endDate = new Date(now);
   666→        endDate.setHours(23, 59, 59, 999);
   667→
   668→        const entries = await timeTrackingDb.getEntriesByDateRange(startDate, endDate);
   669→
   670→        // Group entries by date
   671→        const entriesByDate = new Map<string, TimeEntry[]>();
   672→        entries.forEach(entry => {
   673→          const date = new Date(entry.startTime).toISOString().split('T')[0];
   674→          if (!entriesByDate.has(date)) {
   675→            entriesByDate.set(date, []);
   676→          }
   677→          entriesByDate.get(date)!.push(entry);
   678→        });
   679→
   680→        // Create daily summaries for last N days
   681→        const summaries: DailySummary[] = [];
   682→        for (let i = days - 1; i >= 0; i--) {
   683→          const date = new Date(now);
   684→          date.setDate(date.getDate() - i);
   685→          const dateStr = date.toISOString().split('T')[0];
   686→
   687→          const dayEntries = entriesByDate.get(dateStr) || [];
   688→          const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
   689→
   690→          summaries.push({
   691→            date: dateStr,
   692→            totalDuration,
   693→            entryCount: dayEntries.length
