   756→      getMonthlyReport: async (year, month) => {
   757→        const { projects } = get();
   758→
   759→        // Get all days in month (28-31 days)
   760→        const daysInMonth = new Date(year, month + 1, 0).getDate();
   761→
   762→        // Start of month
   763→        const monthStart = new Date(year, month, 1, 0, 0, 0, 0);
   764→
   765→        // End of month
   766→        const monthEnd = new Date(year, month, daysInMonth, 23, 59, 59, 999);
   767→
   768→        const entries = await timeTrackingDb.getEntriesByDateRange(monthStart, monthEnd);
   769→
   770→        // Group entries by date
   771→        const entriesByDate = new Map<string, TimeEntry[]>();
   772→        entries.forEach(entry => {
   773→          const date = new Date(entry.startTime).toISOString().split('T')[0];
