   778→        });
   779→
   780→        // Create daily breakdown for all days in month
   781→        const dailyBreakdown: DailySummary[] = [];
   782→        for (let day = 1; day <= daysInMonth; day++) {
   783→          const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
   784→          const dayEntries = entriesByDate.get(dateStr) || [];
   785→          const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
   786→
   787→          dailyBreakdown.push({
   788→            date: dateStr,
   789→            totalDuration,
   790→            entryCount: dayEntries.length
   791→          });
   792→        }
   793→
   794→        // Calculate project breakdown
   795→        const projectMap = new Map<string | null, ProjectSummary>();
   796→        const totalTime = entries.reduce((sum, entry) => sum + entry.duration, 0);
   797→
   798→        entries.forEach(entry => {
   799→          const projectId = entry.projectId || null;
   800→
   801→          if (!projectMap.has(projectId)) {
   802→            const project = projectId ? projects.find(p => p.id === projectId) : null;
   803→            projectMap.set(projectId, {
   804→              projectId,
   805→              projectName: project?.name || 'No Project',
   806→              projectColor: project?.color || '#94A3B8', // Default gray
   807→              totalDuration: 0,
   808→              entryCount: 0,
   809→              percentage: 0
   810→            });
   811→          }
   812→
   813→          const summary = projectMap.get(projectId)!;
   814→          summary.totalDuration += entry.duration;
   815→          summary.entryCount += 1;
   816→        });
   817→
   818→        // Calculate percentages
   819→        const projectBreakdown = Array.from(projectMap.values()).map(summary => ({
   820→          ...summary,
   821→          percentage: totalTime > 0 ? (summary.totalDuration / totalTime) * 100 : 0
   822→        }));
   823→
   824→        // Sort by duration descending
   825→        projectBreakdown.sort((a, b) => b.totalDuration - a.totalDuration);
   826→
   827→        return {
   828→          year,
   829→          month,
   830→          totalDuration: totalTime,
   831→          entryCount: entries.length,
   832→          dailyBreakdown,
   833→          projectBreakdown
