   876→        // CSV Header
   877→        const header = 'Date,Start Time,End Time,Duration,Description,Project,Notes\n';
   878→
   879→        // CSV Rows
   880→        const rows = entries.map(entry => {
   881→          const startDate = new Date(entry.startTime);
   882→          const endDate = entry.endTime ? new Date(entry.endTime) : null;
   883→
   884→          const date = startDate.toLocaleDateString('en-US', {
   885→            year: 'numeric',
