   904→          const minutes = Math.floor((entry.duration % 3600) / 60);
   905→          const duration = `${hours}h ${minutes.toString().padStart(2, '0')}m`;
   906→
   907→          const project = entry.projectId
   908→            ? projects.find(p => p.id === entry.projectId)?.name || ''
   909→            : '';
   910→
   911→          // Escape commas and quotes in text fields
   912→          const escapeCSV = (str: string) => {
   913→            if (!str) return '';
   914→            if (str.includes(',') || str.includes('"') || str.includes('\n')) {
   915→              return `"${str.replace(/"/g, '""')}"`;
   916→            }
   917→            return str;
