     1→/**
     2→ * AI Provider Router
     3→ * Routes messages to appropriate providers with automatic fallback support
     4→ * Handles provider failures, rate limits, and intelligent routing
     5→ */
     6→
     7→import type {
     8→  AIProvider,
     9→  AIMessageOptions,
    10→  AIResponse,
    11→  ProviderRouterConfig,
    12→} from './types';
    13→import { ProviderError, ProviderErrorType } from './types';
    14→import { openRouterProvider } from './openRouterProvider';
    15→import { groqProvider } from './groqProvider';
    16→import { huggingFaceProvider } from './huggingFaceProvider';
    17→import { mistralProvider } from './mistralProvider';
    18→import { geminiProvider } from './geminiProvider';
    19→import { openaiProvider } from './openaiProvider';
    20→import { anthropicProvider } from './anthropicProvider';
    21→import { xaiProvider } from './xaiProvider';
    22→
    23→/**
    24→ * Fallback notification callback
    25→ */
    26→export type FallbackCallback = (
    27→  failedProvider: string,
    28→  failedModel: string,
    29→  nextProvider: string,
    30→  nextModel: string,
    31→  reason: string
    32→) => void;
    33→
    34→/**
    35→ * Provider registry
    36→ */
    37→const PROVIDERS: Record<string, AIProvider> = {
    38→  openrouter: openRouterProvider,
    39→  groq: groqProvider,
    40→  huggingface: huggingFaceProvider,
    41→  mistral: mistralProvider,
    42→  gemini: geminiProvider,
    43→  openai: openaiProvider,
    44→  anthropic: anthropicProvider,
    45→  xai: xaiProvider,
    46→};
    47→
    48→/**
    49→ * Default fallback order (best to worst)
    50→ */
    51→const DEFAULT_FALLBACK_ORDER = [
    52→  'openrouter', // Best flexibility
    53→  'groq', // Best speed
    54→  'huggingface', // Free fallback
    55→  'mistral', // European option
    56→  'gemini', // Google fallback
    57→];
    58→
    59→/**
    60→ * AI Provider Router
    61→ * Manages provider selection and automatic fallbacks
    62→ */
    63→export class AIProviderRouter {
    64→  private config: ProviderRouterConfig;
    65→  private onFallback?: FallbackCallback;
    66→
    67→  constructor(config: ProviderRouterConfig, onFallback?: FallbackCallback) {
    68→    this.config = config;
    69→    this.onFallback = onFallback;
    70→  }
    71→
    72→  /**
    73→   * Update router configuration
    74→   */
    75→  updateConfig(config: Partial<ProviderRouterConfig>): void {
    76→    this.config = { ...this.config, ...config };
    77→  }
    78→
    79→  /**
    80→   * Get provider by ID
    81→   */
    82→  getProvider(providerId: string): AIProvider | null {
    83→    return PROVIDERS[providerId] || null;
    84→  }
    85→
    86→  /**
    87→   * Get all providers
    88→   */
    89→  getAllProviders(): Record<string, AIProvider> {
    90→    return PROVIDERS;
    91→  }
    92→
    93→  /**
    94→   * Get configured providers (those with API keys)
    95→   */
    96→  getConfiguredProviders(): AIProvider[] {
    97→    return Object.values(PROVIDERS).filter((provider) => provider.isConfigured());
    98→  }
    99→
   100→  /**
   101→   * Get primary provider
   102→   */
   103→  getPrimaryProvider(): AIProvider | null {
   104→    return this.getProvider(this.config.primaryProvider);
   105→  }
   106→
   107→  /**
   108→   * Get fallback providers in order
   109→   */
   110→  getFallbackProviders(): AIProvider[] {
   111→    const fallbackOrder = this.config.fallbackOrder.length > 0
   112→      ? this.config.fallbackOrder
   113→      : DEFAULT_FALLBACK_ORDER;
   114→
   115→    return fallbackOrder
   116→      .filter((id) => id !== this.config.primaryProvider) // Exclude primary
   117→      .map((id) => this.getProvider(id))
   118→      .filter((provider): provider is AIProvider => provider !== null && provider.isConfigured());
   119→  }
   120→
   121→  /**
