     1→/**
     2→ * Brain Backup Service
     3→ *
     4→ * Handles export/import of all user data to/from .brain files
     5→ * .brain files are JSON files with all user data in a single package
     6→ * Supports compression for smaller file sizes
     7→ */
     8→
     9→import { indexedDBService } from './indexedDB';
    10→
    11→// Extend Window interface for File System Access API
    12→declare global {
    13→  interface Window {
    14→    showDirectoryPicker?: (options?: { mode?: 'read' | 'readwrite' }) => Promise<FileSystemDirectoryHandle>;
    15→  }
    16→}
    17→
    18→export interface BrainBackup {
    19→  version: string;
    20→  exportDate: string;
    21→  appVersion: string;
    22→  compressed?: boolean;
    23→  data: Record<string, any>;
    24→}
    25→
    26→export interface ExportOptions {
    27→  compressed?: boolean;
    28→  prettyPrint?: boolean;
    29→}
    30→
    31→export interface ExportResult {
    32→  filename: string;
    33→  size: number;
    34→  compressed: boolean;
    35→}
    36→
    37→const APP_VERSION = '2.0.0';
    38→const BACKUP_VERSION = '1.0';
    39→
    40→/**
    41→ * Compress data using gzip
    42→ */
    43→const compressData = async (data: string): Promise<Blob> => {
    44→  const blob = new Blob([data]);
    45→  const stream = blob.stream();
    46→  const compressedStream = stream.pipeThrough(new CompressionStream('gzip'));
    47→  return new Response(compressedStream).blob();
    48→};
    49→
    50→/**
    51→ * Decompress gzip data
    52→ */
    53→const decompressData = async (blob: Blob): Promise<string> => {
    54→  const stream = blob.stream();
    55→  const decompressedStream = stream.pipeThrough(new DecompressionStream('gzip'));
    56→  return new Response(decompressedStream).text();
    57→};
    58→
    59→/**
    60→ * Format bytes to human-readable size
    61→ */
    62→export const formatFileSize = (bytes: number): string => {
    63→  if (bytes === 0) return '0 Bytes';
    64→  const k = 1024;
    65→  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    66→  const i = Math.floor(Math.log(bytes) / Math.log(k));
    67→  return `${Math.round((bytes / Math.pow(k, i)) * 100) / 100} ${sizes[i]}`;
    68→};
    69→
    70→/**
    71→ * Optimize object for compression
    72→ * - Sorts keys alphabetically (helps gzip find patterns)
    73→ * - Removes empty objects/arrays (reduces JSON size)
    74→ * - Recursively processes nested objects
    75→ */
    76→const optimizeForCompression = (obj: any): any => {
    77→  if (obj === null || obj === undefined) return obj;
    78→
    79→  if (Array.isArray(obj)) {
    80→    // Process array items, filter out empty objects/arrays
    81→    return obj
    82→      .map(item => optimizeForCompression(item))
    83→      .filter(item => {
    84→        if (item === null || item === undefined) return false;
    85→        if (typeof item === 'object' && Object.keys(item).length === 0) return false;
    86→        if (Array.isArray(item) && item.length === 0) return false;
    87→        return true;
    88→      });
    89→  }
    90→
    91→  if (typeof obj === 'object') {
    92→    // Sort keys and process values
    93→    const sorted: Record<string, any> = {};
    94→    const keys = Object.keys(obj).sort();
    95→
    96→    for (const key of keys) {
    97→      const value = optimizeForCompression(obj[key]);
    98→      // Only include non-empty values
    99→      if (value !== null && value !== undefined) {
   100→        if (typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length === 0) {
   101→          continue; // Skip empty objects
   102→        }
   103→        if (Array.isArray(value) && value.length === 0) {
   104→          continue; // Skip empty arrays
   105→        }
   106→        sorted[key] = value;
   107→      }
   108→    }
   109→
   110→    return sorted;
   111→  }
   112→
   113→  return obj;
   114→};
   115→
   116→/**
   117→ * Export all data to a .brain file
   118→ */
   119→export const exportBrainFile = async (options: ExportOptions = {}): Promise<ExportResult> => {
   120→  const { compressed = true, prettyPrint = false } = options;
   121→
   122→  try {
   123→    console.log('📦 Exporting brain data...');
   124→
   125→    // Get all data from IndexedDB
   126→    const allData = await indexedDBService.getAllData();
   127→
   128→    // Parse JSON values for cleaner export
   129→    const parsedData: Record<string, any> = {};
   130→    for (const [key, value] of Object.entries(allData)) {
   131→      try {
   132→        parsedData[key] = JSON.parse(value);
   133→      } catch {
   134→        // If not JSON, store as-is
   135→        parsedData[key] = value;
   136→      }
   137→    }
   138→
   139→    // Create backup object
   140→    const backup: BrainBackup = {
   141→      version: BACKUP_VERSION,
   142→      exportDate: new Date().toISOString(),
   143→      appVersion: APP_VERSION,
   144→      compressed,
   145→      data: parsedData,
   146→    };
   147→
   148→    // Optimize for compression if enabled (sorts keys, removes empty values)
   149→    const finalBackup = compressed ? optimizeForCompression(backup) : backup;
   150→
   151→    // Convert to JSON string
   152→    const jsonString = JSON.stringify(finalBackup, null, prettyPrint ? 2 : 0);
   153→
   154→    // Create blob (compressed or uncompressed)
   155→    let blob: Blob;
   156→    let fileSize: number;
   157→
   158→    if (compressed) {
   159→      blob = await compressData(jsonString);
   160→      fileSize = blob.size;
   161→      console.log(`📦 Compressed: ${formatFileSize(jsonString.length)} → ${formatFileSize(fileSize)}`);
