   159→/**
   160→ * Dashboard Page - Personal overview
   161→ */
   162→export const Dashboard: React.FC = () => {
   163→  const [hasData, setHasData] = useState(true);
   164→  const [showBackupReminder, setShowBackupReminder] = useState(false);
   165→  const [showWidgetManager, setShowWidgetManager] = useState(false);
   166→  const [showPresetManager, setShowPresetManager] = useState(false);
   167→  const [showBackgroundCustomizer, setShowBackgroundCustomizer] = useState(false);
   168→  const [activeId, setActiveId] = useState<string | null>(null);
   169→
   170→  // Background settings (persisted to localStorage)
   171→  const [bgSettings, setBgSettings] = useState<BackgroundSettings>(() => {
   172→    const saved = localStorage.getItem('dashboard-background');
   173→    return saved
   174→      ? JSON.parse(saved)
   175→      : { type: 'none', value: '', opacity: 100, blur: 0 };
   176→  });
   177→  const enabledWidgets = useWidgetStore((state) => state.enabledWidgets);
   178→  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
   179→  const reorderWidgets = useWidgetStore((state) => state.reorderWidgets);
   180→
   181→  // Configure drag sensors (require 5px movement to prevent accidental drags)
   182→  const sensors = useSensors(
   183→    useSensor(PointerSensor, {
   184→      activationConstraint: {
   185→        distance: 5,
   186→      },
   187→    })
   188→  );
   189→
   190→  // Handle drag start - track active widget for ghost preview
   191→  const handleDragStart = (event: DragStartEvent) => {
   192→    setActiveId(event.active.id as string);
   193→  };
   194→
   195→  // Handle drag end - reorder widgets
   196→  const handleDragEnd = (event: DragEndEvent) => {
   197→    const { active, over } = event;
   198→
   199→    if (over && active.id !== over.id) {
   200→      const oldIndex = enabledWidgets.indexOf(active.id as string);
   201→      const newIndex = enabledWidgets.indexOf(over.id as string);
   202→
   203→      if (oldIndex !== -1 && newIndex !== -1) {
   204→        const newOrder = [...enabledWidgets];
   205→        const [movedItem] = newOrder.splice(oldIndex, 1);
   206→        newOrder.splice(newIndex, 0, movedItem);
   207→        reorderWidgets(newOrder);
   208→      }
   209→    }
   210→
   211→    setActiveId(null);
   212→  };
   213→
   214→  useEffect(() => {
   215→    document.title = 'Neuman Brain';
   216→
   217→    // Check for hash navigation (#customize-widgets)
   218→    if (window.location.hash === '#customize-widgets') {
   219→      setShowWidgetManager(true);
   220→      // Clear the hash
   221→      window.history.replaceState(null, '', window.location.pathname);
   222→    }
   223→
   224→    // Check if user has any data
   225→    const checkForData = async () => {
   226→      try {
   227→        const keys = await indexedDBService.getAllKeys();
   228→        const hasAnyData = keys.length > 0;
   229→        setHasData(hasAnyData);
   230→
   231→        // Show backup reminder if no data AND not dismissed
   232→        const dismissed = localStorage.getItem('dashboard-backup-reminder-dismissed');
   233→        if (!hasAnyData && !dismissed) {
   234→          setShowBackupReminder(true);
   235→        }
   236→      } catch (error) {
   237→        console.error('Failed to check for data:', error);
   238→      }
   239→    };
   240→
   241→    checkForData();
   242→  }, []);
   243→
   244→  const handleDismissReminder = () => {
   245→    setShowBackupReminder(false);
   246→    localStorage.setItem('dashboard-backup-reminder-dismissed', 'true');
   247→  };
   248→
   249→  const handleBackgroundChange = (newSettings: BackgroundSettings) => {
   250→    setBgSettings(newSettings);
   251→    localStorage.setItem('dashboard-background', JSON.stringify(newSettings));
   252→  };
   253→
   254→  return (
   255→    <div className="dashboard-page relative">
   256→      {/* Background Layer */}
   257→      {bgSettings.type !== 'none' && (
   258→        <div
   259→          className="dashboard-background fixed inset-0 pointer-events-none"
   260→          style={{
   261→            backgroundImage: bgSettings.value,
   262→            backgroundSize: bgSettings.type === 'image' ? 'cover' : undefined,
   263→            backgroundPosition: bgSettings.type === 'image' ? 'center' : undefined,
   264→            backgroundAttachment: 'fixed',
   265→            opacity: bgSettings.opacity / 100,
   266→            filter: `blur(${bgSettings.blur}px)`,
   267→            zIndex: -1,
   268→          }}
   269→        />
   270→      )}
   271→
   272→      <div className="mb-4 sm:mb-8">
   273→        <h1 className="text-lg sm:text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-1 sm:mb-2">
   274→          Dashboard
   275→        </h1>
   276→        <p className="text-sm sm:text-base text-text-light-secondary dark:text-text-dark-secondary mb-2 sm:mb-3">
   277→          Your personal management overview
   278→        </p>
   279→        <div className="flex gap-2">
   280→          <button
   281→            onClick={() => setShowBackgroundCustomizer(true)}
   282→            className="px-3 py-1.5 text-sm bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors"
   283→            title="Customize background"
   284→          >
   285→            🎨 Background
   286→          </button>
   287→          <button
   288→            onClick={() => setShowPresetManager(true)}
   289→            className="px-3 py-1.5 text-sm bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors"
   290→            title="Manage layout presets"
   291→          >
   292→            📐 Presets
   293→          </button>
   294→        </div>
   295→      </div>
   296→
   297→      {/* First-Time User Backup Reminder */}
   298→      {showBackupReminder && !hasData && (
   299→        <div className="mb-6 p-6 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border-2 border-yellow-400 dark:border-yellow-600">
   300→          <div className="flex items-start gap-4">
   301→            <span className="text-3xl">⚠️</span>
   302→            <div className="flex-1">
   303→              <h3 className="text-xl font-bold text-yellow-900 dark:text-yellow-300 mb-2">
   304→                Welcome to Neuman Brain!
   305→              </h3>
   306→              <p className="text-sm text-yellow-800 dark:text-yellow-400 mb-3">
   307→                <strong>Important:</strong> Your data is stored locally in this browser. To protect your work, remember to create regular backups!
   308→              </p>
   309→              <div className="bg-white dark:bg-surface-dark-elevated p-4 rounded-lg mb-4">
   310→                <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   311→                  Quick Start:
   312→                </p>
   313→                <ol className="text-sm text-text-light-secondary dark:text-text-dark-secondary space-y-1 list-decimal list-inside ml-2">
   314→                  <li>Start creating tasks, notes, and plans</li>
   315→                  <li>When you have data to protect, go to Settings → Backup</li>
   316→                  <li>Export your first backup (Chrome/Edge: enable Auto-Save!)</li>
   317→                  <li>Store your .brain file somewhere safe (cloud, USB, etc.)</li>
   318→                </ol>
   319→              </div>
   320→              <button
   321→                onClick={handleDismissReminder}
   322→                className="px-4 py-2 bg-yellow-600 hover:bg-yellow-700 text-white rounded-lg font-medium"
   323→              >
   324→                Got It!
   325→              </button>
   326→            </div>
   327→          </div>
   328→        </div>
   329→      )}
   330→
   331→      {/* Dashboard Grid Layout - CSS Grid with column spanning + drag-drop */}
   332→      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
   333→        <SortableContext items={enabledWidgets} strategy={verticalListSortingStrategy}>
   334→          {enabledWidgets.length > 0 ? (
   335→            <div className="dashboard-grid grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-6 auto-rows-min" style={{ gridAutoFlow: 'dense' }}>
   336→              {enabledWidgets.map((widgetId) => {
   337→                // Handle dynamic widget instances (e.g., github-1, github-2)
   338→                const baseWidgetType = widgetId.includes('-') && widgetId.match(/^([a-z]+)-\d+$/)
   339→                  ? widgetId.split('-')[0]
   340→                  : widgetId;
   341→
   342→                const WidgetComponent = WIDGET_COMPONENTS[baseWidgetType];
   343→                if (!WidgetComponent) return null;
   344→
   345→                // Pass widgetId prop for dynamic instances
   346→                const isDynamicInstance = widgetId !== baseWidgetType;
   347→
   348→                // Get widget size (default to 1x)
   349→                // In 2-column grid: 1x = 1 column (50%), 2x = 2 columns (100%), 3x = 2 columns (100%)
   350→                const size = widgetSizes[widgetId] || 1;
   351→                const sizeClass = size >= 2 ? 'md:col-span-2' : '';
   352→
   353→                return (
   354→                  <SortableWidget key={widgetId} id={widgetId} className={sizeClass}>
   355→                    <WidgetErrorBoundary widgetId={widgetId}>
   356→                      <Suspense fallback={<WidgetLoader />}>
   357→                        {isDynamicInstance ? (
   358→                          <WidgetComponent widgetId={widgetId} />
   359→                        ) : (
   360→                          <WidgetComponent />
   361→                        )}
   362→                      </Suspense>
   363→                    </WidgetErrorBoundary>
   364→                  </SortableWidget>
   365→                );
   366→              })}
   367→            </div>
   368→          ) : (
   369→            <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   370→              <p className="text-lg mb-4">No widgets enabled.</p>
   371→              <p className="text-sm">
   372→                Click the ⚙ icon next to "Dashboard" in the sidebar to customize widgets.
   373→              </p>
   374→            </div>
   375→          )}
   376→        </SortableContext>
   377→
   378→        {/* Ghost Preview during Drag */}
   379→        <DragOverlay>
   380→          {activeId ? (
   381→            <div className="bg-surface-light-elevated dark:bg-surface-dark-elevated border-2 border-accent-blue dark:border-accent-cyan rounded-lg p-6 shadow-2xl opacity-80">
   382→              <div className="flex items-center gap-2 text-text-light-primary dark:text-text-dark-primary font-medium">
   383→                <svg
   384→                  width="16"
   385→                  height="16"
   386→                  viewBox="0 0 16 16"
   387→                  fill="none"
   388→                  xmlns="http://www.w3.org/2000/svg"
   389→                  className="text-accent-blue dark:text-accent-cyan"
   390→                >
   391→                  <circle cx="6" cy="4" r="1.5" fill="currentColor" />
   392→                  <circle cx="10" cy="4" r="1.5" fill="currentColor" />
   393→                  <circle cx="6" cy="8" r="1.5" fill="currentColor" />
   394→                  <circle cx="10" cy="8" r="1.5" fill="currentColor" />
   395→                  <circle cx="6" cy="12" r="1.5" fill="currentColor" />
   396→                  <circle cx="10" cy="12" r="1.5" fill="currentColor" />
   397→                </svg>
   398→                <span>Moving widget...</span>
   399→              </div>
   400→            </div>
   401→          ) : null}
   402→        </DragOverlay>
   403→      </DndContext>
   404→
   405→      {/* Widget Manager Modal */}
   406→      <WidgetManager isOpen={showWidgetManager} onClose={() => setShowWidgetManager(false)} />
   407→
   408→      {/* Preset Manager Modal */}
   409→      <PresetManager isOpen={showPresetManager} onClose={() => setShowPresetManager(false)} />
   410→
   411→      {/* Background Customizer Modal */}
   412→      <BackgroundCustomizer
   413→        isOpen={showBackgroundCustomizer}
   414→        onClose={() => setShowBackgroundCustomizer(false)}
   415→        settings={bgSettings}
   416→        onSettingsChange={handleBackgroundChange}
   417→      />
   418→    </div>
   419→  );
