   388→                  <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   389→                    <ReactMarkdown>{streamingContent}</ReactMarkdown>
