/**
 * AI Terminal Component
 * Persistent AI assistant with multi-provider chat interface
 *
 * Features:
 * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
 * - Provider/model selection
 * - Automatic fallback on errors
 * - Usage tracking
 * - Encrypted API key storage
 */

import React, { useState, useRef, useEffect } from 'react';
import { useTerminalStore } from '../stores/useTerminalStore';
import { aiTerminalService } from '../services/aiTerminal';
import { createDefaultRouter } from '../services/ai/providerRouter';
import { ProviderSettings } from './ProviderSettings';
import { ModelSelector } from './ModelSelector';
import { UsageTracker } from './UsageTracker';
import ReactMarkdown from 'react-markdown';

export const AITerminal: React.FC = () => {
  const {
    isOpen,
    apiKey, // Legacy Gemini key
    // model is legacy and unused - destructured but not assigned to avoid TS error
    activeProvider,
    activeModel,
    providers,
    encryptionPassword,
    isPasswordExpired,
    fallbackEnabled,
    messages,
    isStreaming,
    setOpen,
    setActiveProvider,
    addMessage,
    clearMessages,
    setStreaming,
  } = useTerminalStore();

  const [input, setInput] = useState('');
  const [streamingContent, setStreamingContent] = useState('');
  const [showProviderSettings, setShowProviderSettings] = useState(false);
  const [showModelSelector, setShowModelSelector] = useState(false);
  const [showUsageTracker, setShowUsageTracker] = useState(false);
  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  // Initialize provider router
  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
    // Fallback notification callback
    setFallbackNotification(
      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
    );
    setTimeout(() => setFallbackNotification(null), 5000);
  }));

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, streamingContent]);

  // Focus input when terminal opens
  useEffect(() => {
    if (isOpen) {
      inputRef.current?.focus();
    }
  }, [isOpen]);

  // Initialize AI service with API key (legacy Gemini)
  useEffect(() => {
    if (apiKey) {
      aiTerminalService.setApiKey(apiKey);
    }
  }, [apiKey]);

  // Configure router with active provider and model
  useEffect(() => {
    router.updateConfig({
      primaryProvider: activeProvider,
      primaryModel: activeModel,
      fallbackEnabled: fallbackEnabled,
    });
  }, [activeProvider, activeModel, fallbackEnabled, router]);

  // Initialize provider API keys from encrypted storage
  useEffect(() => {
    const initializeApiKeys = async () => {
      if (encryptionPassword && !isPasswordExpired()) {
        const allProviders = router.getAllProviders();
        for (const [providerId, provider] of Object.entries(allProviders)) {
          const providerConfig = providers[providerId];
          if (providerConfig && providerConfig.encryptedApiKey) {
            try {
              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
              if (decryptedKey) {
                provider.setApiKey(decryptedKey);
              }
            } catch (error) {
              console.error(`Failed to decrypt ${providerId} API key:`, error);
            }
          }
        }
      }
    };

    initializeApiKeys();
  }, [encryptionPassword, isPasswordExpired, providers, router]);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd/Ctrl + Shift + A to toggle terminal
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
        e.preventDefault();
        setOpen(!isOpen);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, setOpen]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isStreaming) return;

    const userMessage = input.trim();
    setInput('');

    // Check if any provider is configured
    const configuredProviders = router.getConfiguredProviders();
    if (configuredProviders.length === 0) {
      addMessage({
        role: 'system',
        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
      });
      return;
    }

    // Check if active provider is configured
    const activeProviderObj = router.getProvider(activeProvider);
    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
      addMessage({
        role: 'system',
        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
      });
      return;
    }

    // Add user message
    addMessage({
      role: 'user',
      content: userMessage,
    });

    // Start streaming
    setStreaming(true);
    setStreamingContent('');

    try {
      // Send message using router (with automatic fallback)
      const response = await router.sendMessage({
        prompt: userMessage,
        conversationHistory: messages.map((msg) => ({
          role: msg.role as 'user' | 'assistant' | 'system',
          content: msg.content,
        })),
        stream: true,
        onChunk: (chunk) => {
          setStreamingContent((prev) => prev + chunk);
        },
      });

      // Add complete assistant message with provider/model metadata
      addMessage({
        role: 'assistant',
        content: response.content,
        provider: response.provider || activeProvider,
        model: response.model || activeModel,
      });
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
      addMessage({
        role: 'system',
        content: `❌ Error: ${errorMessage}`,
      });
    } finally{
      setStreaming(false);
      setStreamingContent('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  if (!isOpen) return null;

  return (
    <div
      className={`
        fixed top-0 right-0 h-screen
        transition-transform duration-200 ease-in-out
        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
        w-[300px] lg:w-[375px]
        bg-white dark:bg-black
        border-l border-border-light dark:border-border-dark
        shadow-2xl
        z-40
        flex flex-col
      `}
    >
      {/* Header - Terminal Style */}
      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
        <div className="flex items-center gap-2 font-mono text-sm">
          <span>user@neuman-brain:~$</span>
          <span className="text-green-400 text-xs">
            {router.getConfiguredProviders().length > 0
              ? `${activeProvider}/${activeModel}`
              : 'no-provider'}
          </span>
        </div>

        <div className="flex items-center gap-1">
          {/* Fallback indicator */}
          {fallbackEnabled && router.getConfiguredProviders().length > 1 && (
            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded-button font-mono" title="Automatic fallback enabled">
              🔄
            </span>
          )}

          {/* Usage Tracker */}
          <button
            onClick={() => setShowUsageTracker(!showUsageTracker)}
            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
            title="Usage Statistics"
            aria-label="View usage statistics"
          >
            📊
          </button>

          {/* Model Selector */}
          <button
            onClick={() => setShowModelSelector(!showModelSelector)}
            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
            title="Select Model"
            aria-label="Select AI model"
          >
            🔀
          </button>

          {/* Provider Settings */}
          <button
            onClick={() => setShowProviderSettings(true)}
            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
            title="Provider Settings"
            aria-label="Open provider settings"
          >
            ⚙️
          </button>

          {/* Close */}
          <button
            onClick={() => setOpen(false)}
            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-base"
            title="Close Terminal"
            aria-label="Close AI terminal"
          >
            ✕
          </button>
        </div>
      </div>

      {/* Chat Content */}
      <div className="flex flex-col flex-1 overflow-hidden">
        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {/* Fallback Notification */}
            {fallbackNotification && (
              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-button text-sm text-text-light-primary dark:text-text-dark-primary">
                {fallbackNotification}
              </div>
            )}

            {messages.length === 0 && router.getConfiguredProviders().length === 0 && (
              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
                <p className="text-sm mb-4">
                  Configure AI providers to get started. Choose from 8 providers including free options!
                </p>
                <button
                  onClick={() => setShowProviderSettings(true)}
                  className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
                >
                  ⚙️ Configure Providers
                </button>
                <div className="mt-4 text-xs space-y-1">
                  <p className="font-medium">Free Providers Available:</p>
                  <p>• OpenRouter (Llama 3.3, Gemini 2.0)</p>
                  <p>• Groq (Lightning-fast inference)</p>
                  <p>• HuggingFace (Thousands of models)</p>
                  <p>• Mistral (European AI)</p>
                </div>
              </div>
            )}

            {messages.length === 0 && router.getConfiguredProviders().length > 0 && (
              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
                <p className="text-lg font-semibold mb-2">AI Terminal Ready</p>
                <p className="text-sm mb-2">
                  Active: <span className="font-medium text-accent-blue">{activeProvider}</span> • {activeModel}
                </p>
                <p className="text-sm">Ask me anything! I can help with:</p>
                <ul className="text-sm mt-2 space-y-1">
                  <li>💬 General questions & conversation</li>
                  <li>💻 Code generation & explanation</li>
                  <li>🔧 Debugging & problem solving</li>
                  <li>📝 Writing & productivity</li>
                  <li>🔄 Automatic fallback if provider fails</li>
                </ul>
              </div>
            )}

            {messages.map((message) => (
              <div
                key={message.id}
                className={`flex gap-3 ${
                  message.role === 'user' ? 'justify-end' : 'justify-start'
                }`}
              >
                {message.role !== 'user' && (
                  <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
                    {message.role === 'system' ? '⚠️' : '🤖'}
                  </div>
                )}

                <div
                  className={`max-w-[80%] rounded-button px-4 py-2 font-mono ${
                    message.role === 'user'
                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-white'
                      : message.role === 'system'
                      ? 'bg-yellow-100 dark:bg-yellow-900/30 text-text-light-primary dark:text-text-dark-primary border border-yellow-400 dark:border-yellow-600'
                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400'
                  }`}
                >
                  {message.role === 'assistant' ? (
                    <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
                      <ReactMarkdown>{message.content}</ReactMarkdown>
                    </div>
                  ) : (
                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                  )}
                  <div className="flex items-center gap-2 text-xs opacity-60 mt-1">
                    <span>{new Date(message.timestamp).toLocaleTimeString()}</span>
                    {message.provider && message.model && (
                      <>
                        <span>•</span>
                        <span className="font-medium" title="Provider and model used">
                          {message.provider} • {message.model}
                        </span>
                      </>
                    )}
                  </div>
                </div>

                {message.role === 'user' && (
                  <div className="w-8 h-8 rounded-full bg-accent-magenta flex items-center justify-center text-white flex-shrink-0">
                    👤
                  </div>
                )}
              </div>
            ))}

            {/* Streaming message */}
            {isStreaming && streamingContent && (
              <div className="flex gap-3 justify-start">
                <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
                  🤖
                </div>
                <div className="max-w-[80%] rounded-button px-4 py-2 font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400">
                  <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
                    <ReactMarkdown>{streamingContent}</ReactMarkdown>
                  </div>
                  <div className="flex items-center gap-1 text-xs opacity-60 mt-1">
                    <div className="w-1 h-1 bg-current rounded-full animate-pulse" />
                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-75" />
                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-150" />
                  </div>
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="border-t border-border-light dark:border-border-dark p-3 bg-surface-light dark:bg-black flex-shrink-0">
            <form onSubmit={handleSubmit} className="flex gap-2">
              <textarea
                ref={inputRef}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={
                  router.getConfiguredProviders().length > 0
                    ? 'user@neuman-brain:~$ _'
                    : 'Configure providers first...'
                }
                disabled={router.getConfiguredProviders().length === 0 || isStreaming}
                className="flex-1 px-3 py-2 rounded-button font-mono text-sm bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark text-text-light-primary dark:text-white placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue dark:focus:ring-green-400 focus:border-transparent resize-none"
                rows={1}
              />
              <button
                type="submit"
                disabled={router.getConfiguredProviders().length === 0 || !input.trim() || isStreaming}
                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 dark:disabled:bg-neutral-700 text-white rounded-button font-medium transition-all duration-standard ease-smooth disabled:cursor-not-allowed"
              >
                {isStreaming ? '⋯' : '→'}
              </button>
              {messages.length > 0 && (
                <button
                  type="button"
                  onClick={clearMessages}
                  className="px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark hover:bg-neutral-200 dark:hover:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary rounded-button text-sm transition-all duration-standard ease-smooth"
                  title="Clear chat"
                >
                  🗑️
                </button>
              )}
            </form>
          </div>
        </div>

      {/* Provider Settings Modal */}
      <ProviderSettings
        isOpen={showProviderSettings}
        onClose={() => setShowProviderSettings(false)}
        router={router}
      />

      {/* Model Selector Sliding Panel */}
      {showModelSelector && (
        <div className="absolute top-12 right-0 w-96 max-h-[400px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
          <div className="p-4 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark">
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Select Model
            </h3>
            <button
              onClick={() => setShowModelSelector(false)}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button"
            >
              ✕
            </button>
          </div>
          <div className="p-4 overflow-y-auto max-h-[350px]">
            <ModelSelector
              router={router}
              onSelect={(providerId, modelId) => {
                setActiveProvider(providerId, modelId);
                setShowModelSelector(false);
              }}
              currentProvider={activeProvider}
              currentModel={activeModel}
            />
          </div>
        </div>
      )}

      {/* Usage Tracker Sliding Panel */}
      {showUsageTracker && (
        <div className="absolute top-12 right-0 w-96 max-h-[500px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
          <div className="p-4 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark">
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Usage Tracker
            </h3>
            <button
              onClick={() => setShowUsageTracker(false)}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button"
            >
              ✕
            </button>
          </div>
          <div className="p-4 overflow-y-auto max-h-[450px]">
            <UsageTracker router={router} />
          </div>
        </div>
      )}
    </div>
  );
};

